const input = $input.first().json;
const body = (input && (input.body || input)) || {};
const now = new Date();
const isWebhook = !!(input && (input.headers || input.body));
let monthKey = body.monthKey;
if (!monthKey) {
  if (isWebhook) {
    monthKey = now.toISOString().slice(0, 7);
  } else {
    const prev = new Date(now.getFullYear(), now.getMonth() - 1, 1);
    monthKey = prev.toISOString().slice(0, 7);
  }
}
return [{ json: { monthKey, isWebhook } }];

const txs = $input.first().json.txs || [];
const monthKey = $('Determine Month').first().json.monthKey;
const monthNames = ['январь','февраль','март','апрель','май','июнь','июль','август','сентябрь','октябрь','ноябрь','декабрь'];
const [yyyy, mm] = monthKey.split('-');
const monthName = monthNames[parseInt(mm) - 1] || mm;
const fmt = n => n.toLocaleString('ru-RU', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

if (!txs.length) {
  return [{ json: { text: '💰 Финансы — ' + monthName + ' ' + yyyy + '\n\nПо Альфе нет транзакций.', monthKey, totalIn: 0, totalOut: 0, byCategory: {} } }];
}

// Раздельная агрегация: поступления и списания
const incomes = txs.filter(t => t.direction === 'in');
const spends  = txs.filter(t => t.direction !== 'in');
const totalIn  = incomes.reduce((s, t) => s + (Number(t.amount) || 0), 0);
const totalOut = spends.reduce ((s, t) => s + (Number(t.amount) || 0), 0);

// Бакеты только по списаниям
const buckets = {};
for (const t of spends) {
  const c = t.category || '⚠️ Без категории';
  if (!buckets[c]) buckets[c] = { sum: 0, count: 0 };
  buckets[c].sum += Number(t.amount) || 0;
  buckets[c].count += 1;
}
const sorted = Object.entries(buckets).sort((a, b) => b[1].sum - a[1].sum);

const lines = ['💰 Финансы — ' + monthName + ' ' + yyyy, ''];
lines.push('📥 Пришло:    +' + fmt(totalIn)  + ' ₽  (' + incomes.length + ' опер.)');
lines.push('💸 Потрачено: −' + fmt(totalOut) + ' ₽  (' + spends.length + ' опер.)');

if (sorted.length) {
  lines.push('');
  lines.push('Структура трат:');
  for (const [cat, agg] of sorted) {
    const pct = totalOut > 0 ? Math.round(agg.sum / totalOut * 100) : 0;
    lines.push(cat + ' — ' + fmt(agg.sum) + ' ₽ (' + pct + '%, ' + agg.count + ')');
  }
}

const unc = spends.filter(t => !t.category);
if (unc.length) {
  lines.push('');
  lines.push('🔍 Без категории: ' + unc.length + ' шт. — нажми кнопки в карточках транзакций.');
  for (const t of unc.slice(0, 10)) {
    lines.push('· ' + fmt(t.amount) + ' ₽ — MCC ' + (t.mcc || '?') + ' — ' + (t.purpose || '').slice(0, 80));
  }
  if (unc.length > 10) lines.push('… и ещё ' + (unc.length - 10));
}

const byCategory = {};
for (const [cat, agg] of sorted) byCategory[cat] = { sum: agg.sum, count: agg.count };

return [{ json: { text: lines.join('\n'), monthKey, totalIn, totalOut, count: txs.length, byCategory } }];
